1	//! The individual wellformedness checks. Each produces zero or one `WfError`
2	//! (one topic block). Message bodies reproduce oracle byte formatting.
3	
4	use crate::ast::*;
5	use crate::pretty::{pp_fact, pp_term, pp_var};
6	use crate::report::WfError;
7	
8	// ---- Topic strings (exact, including significant whitespace) ----
9	pub const T_UNBOUND: &str = "Unbound variables";
10	pub const T_PUBNAMES: &str = "Public constants with mismatching capitalization";
11	pub const T_SORTS: &str = "Variable with mismatching sorts or capitalization";
12	pub const T_RESERVED: &str = "Reserved names";
13	pub const T_FR: &str = "Fr facts must only use a fresh- or a msg-variable";
14	pub const T_SPECIAL: &str = "Special facts";
15	pub const T_ARITY: &str = "Fact arity issues";
16	pub const T_MULT: &str = "Fact multiplicity issues";
17	pub const T_LHSRHS: &str = "Facts occur in the left-hand-side but not in any right-hand-side ";
18	pub const T_FORMULA_TERMS: &str = "Formula terms";
19	pub const T_GUARD: &str = " Formula guardedness";
20	pub const T_NAT: &str = "Nat Sorts";
21	pub const T_SUBTERM: &str = "Subterm Convergence Warning";
22	
23	/// Reserved fact names (used as protocol facts -> "Reserved names").
24	const RESERVED_FACTS: &[&str] = &["K", "KU", "KD"];
25	/// Special I/O facts handled by the special-fact / Fr checks.
26	const SPECIAL_FACTS: &[&str] = &["In", "Out", "Fr"];
27	
28	fn is_reserved(name: &str) -> bool {
29	    RESERVED_FACTS.contains(&name)
30	}
31	fn is_special(name: &str) -> bool {
32	    SPECIAL_FACTS.contains(&name)
33	}
34	fn is_builtin_factname(name: &str) -> bool {
35	    is_reserved(name) || is_special(name)
36	}
37	
38	// ---------------------------------------------------------------------------
39	// AST traversal helpers
40	// ---------------------------------------------------------------------------
41	
42	/// The protocol rules of a theory (excludes intruder rules).
43	pub fn protocol_rules(thy: &Theory) -> Vec<&Rule> {
44	    thy.items
45	        .iter()
46	        .filter_map(|it| match it {
47	            TheoryItem::Rule(r) => Some(r),
48	            _ => None,
49	        })
50	        .collect()
51	}
52	
53	fn collect_term_vars(t: &Term, out: &mut Vec<VarSpec>) {
54	    match t {
55	        Term::Var(v) => out.push(v.clone()),
56	        Term::App(_, args) | Term::Pair(args) => {
57	            for a in args {
58	                collect_term_vars(a, out);
59	            }
60	        }
61	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
62	            collect_term_vars(a, out);
63	            collect_term_vars(b, out);
64	        }
65	        Term::PatMatch(inner) => collect_term_vars(inner, out),
66	        _ => {}
67	    }
68	}
69	
70	fn collect_fact_vars(f: &Fact, out: &mut Vec<VarSpec>) {
71	    for a in &f.args {
72	        collect_term_vars(a, out);
73	    }
74	}
75	
76	fn collect_facts_vars(fs: &[Fact], out: &mut Vec<VarSpec>) {
77	    for f in fs {
78	        collect_fact_vars(f, out);
79	    }
80	}
81	
82	/// Collect public-constant literals (name only) from a term.
83	fn collect_pub_lits(t: &Term, out: &mut Vec<String>) {
84	    match t {
85	        Term::PubLit(s) => out.push(s.clone()),
86	        Term::App(_, args) | Term::Pair(args) => {
87	            for a in args {
88	                collect_pub_lits(a, out);
89	            }
90	        }
91	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
92	            collect_pub_lits(a, out);
93	            collect_pub_lits(b, out);
94	        }
95	        Term::PatMatch(inner) => collect_pub_lits(inner, out),
96	        _ => {}
97	    }
98	}
99	
100	fn var_needs_binding(v: &VarSpec) -> bool {
101	    matches!(
102	        v.sort,
103	        SortHint::Fresh | SortHint::Msg | SortHint::Untagged | SortHint::Nat
104	    )
105	}
106	
107	fn var_key(v: &VarSpec) -> (String, u64, i32) {
108	    (v.name.clone(), v.idx, sort_rank(v.sort))
109	}
110	
111	fn sort_rank(s: SortHint) -> i32 {
112	    match s {
113	        SortHint::Msg => 0,
114	        SortHint::Pub => 1,
115	        SortHint::Fresh => 2,
116	        SortHint::Node => 3,
117	        SortHint::Nat => 4,
118	        SortHint::Untagged => 5,
119	        SortHint::Suffix(_) => 6,
120	    }
121	}
122	
123	fn dedup_vars(mut vs: Vec<VarSpec>) -> Vec<VarSpec> {
124	    vs.sort_by_key(var_key);
125	    vs.dedup_by_key(|v| var_key(v));
126	    vs
127	}
128	
129	// ---------------------------------------------------------------------------
130	// 1. Unbound variables
131	// ---------------------------------------------------------------------------
132	pub fn unbound_variables(thy: &Theory) -> Vec<WfError> {
133	    let mut entries: Vec<String> = Vec::new();
134	    for r in protocol_rules(thy) {
135	        // Bound = variables in premises plus let-bound variables.
136	        let mut bound: Vec<VarSpec> = Vec::new();
137	        collect_facts_vars(&r.premises, &mut bound);
138	        for lb in &r.let_block {
139	            collect_term_vars(&lb.var, &mut bound);
140	        }
141	        let bound: std::collections::HashSet<(String, u64, i32)> =
142	            bound.iter().map(var_key).collect();
143	
144	        // Used = variables in actions, conclusions, embedded restrictions,
145	        // and the right-hand-sides of let bindings.
146	        let mut used: Vec<VarSpec> = Vec::new();
147	        collect_facts_vars(&r.actions, &mut used);
148	        collect_facts_vars(&r.conclusions, &mut used);
149	        for lb in &r.let_block {
150	            collect_term_vars(&lb.value, &mut used);
151	        }
152	
153	        let mut unbound: Vec<VarSpec> = used
154	            .into_iter()
155	            .filter(var_needs_binding)
156	            .filter(|v| !bound.contains(&var_key(v)))
157	            .collect();
158	        unbound = dedup_vars(unbound);
159	        // Report order: by base name then index.
160	        unbound.sort_by(|a, b| a.name.cmp(&b.name).then(a.idx.cmp(&b.idx)));
161	
162	        if !unbound.is_empty() {
163	            let names: Vec<String> = unbound.iter().map(pp_var).collect();
164	            entries.push(format!(
165	                "  rule `{}' has unbound variables: \n    {}",
166	                r.name,
167	                names.join(", ")
168	            ));
169	        }
170	    }
171	    if entries.is_empty() {
172	        vec![]
173	    } else {
174	        vec![WfError::new(T_UNBOUND, entries.join("\n  \n"))]
175	    }
176	}
177	
178	// ---------------------------------------------------------------------------
179	// 3. Variable with mismatching sorts or capitalization
180	// ---------------------------------------------------------------------------
181	pub fn mismatching_sorts(thy: &Theory) -> Vec<WfError> {
182	    let mut rule_entries: Vec<String> = Vec::new();
183	    for r in protocol_rules(thy) {
184	        let mut vars: Vec<VarSpec> = Vec::new();
185	        collect_facts_vars(&r.premises, &mut vars);
186	        collect_facts_vars(&r.actions, &mut vars);
187	        collect_facts_vars(&r.conclusions, &mut vars);
188	
189	        // Group by lowercased base name; a group with >1 distinct variant
190	        // (prefix+name, ignoring index) is a conflict.
191	        let mut groups: Vec<(String, Vec<String>)> = Vec::new(); // (lc key, variants)
192	        for v in &vars {
193	            let key = v.name.to_lowercase();
194	            let variant = variant_repr(v);
195	            match groups.iter_mut().find(|(k, _)| *k == key) {
196	                Some((_, variants)) => {
197	                    if !variants.contains(&variant) {
198	                        variants.push(variant);
199	                    }
200	                }
201	                None => groups.push((key, vec![variant])),
202	            }
203	        }
204	        let mut conflicts: Vec<Vec<String>> = groups
205	            .into_iter()
206	            .filter(|(_, vs)| vs.len() > 1)
207	            .map(|(_, mut vs)| {
208	                vs.sort();
209	                vs
210	            })
211	            .collect();
212	        if conflicts.is_empty() {
213	            continue;
214	        }
215	        // deterministic ordering of groups within a rule
216	        conflicts.sort();
217	        let mut body = format!("  rule `{}': ", r.name);
218	        for (i, variants) in conflicts.iter().enumerate() {
219	            body.push_str(&format!("\n    {}. {}", i + 1, variants.join(", ")));
220	        }
221	        rule_entries.push(body);
222	    }
223	    if rule_entries.is_empty() {
224	        return vec![];
225	    }
226	    let header = "Possible reasons:\n1. Identifiers are case sensitive, i.e.,'x' and 'X' are considered to be different.\n2. The same holds for sorts:, i.e., '$x', 'x', and '~x' are considered to be different.\n";
227	    let msg = format!("{}\n{}", header, rule_entries.join("\n  \n"));
228	    vec![WfError::new(T_SORTS, msg)]
229	}
230	
231	/// A variable's sort+name representation without the numeric index.
232	fn variant_repr(v: &VarSpec) -> String {
233	    let prefix = match v.sort {
234	        SortHint::Fresh => "~",
235	        SortHint::Pub => "$",
236	        SortHint::Nat => "%",
237	        SortHint::Node => "#",
238	        _ => "",
239	    };
240	    format!("{}{}", prefix, v.name)
241	}
242	
243	// ---------------------------------------------------------------------------
244	// 4. Reserved names
245	// ---------------------------------------------------------------------------
246	pub fn reserved_names(thy: &Theory) -> Vec<WfError> {
247	    let mut entries: Vec<String> = Vec::new();
248	    for r in protocol_rules(thy) {
249	        // On the left/right the reserved set is {K,KU,KD}; in the middle
250	        // (actions) the I/O facts In/Out/Fr are reserved too (observed z9/z11).
251	        for (facts, phrase, middle) in [
252	            (&r.premises, "left-hand-side", false),
253	            (&r.actions, "the middle", true),
254	            (&r.conclusions, "the right-hand-side", false),
255	        ] {
256	            let hits: Vec<&Fact> = facts
257	                .iter()
258	                .filter(|f| is_reserved(&f.name) || (middle && is_special(&f.name)))
259	                .collect();
260	            if hits.is_empty() {
261	                continue;
262	            }
263	            let rendered: Vec<String> = hits.iter().map(|f| pp_fact(f)).collect();
264	            entries.push(format!(
265	                "  Rule `{}' contains facts with reserved names on {}:\n    {}",
266	                r.name,
267	                phrase,
268	                rendered.join(", ")
269	            ));
270	        }
271	    }
272	    if entries.is_empty() {
273	        vec![]
274	    } else {
275	        vec![WfError::new(T_RESERVED, entries.join("\n  \n"))]
276	    }
277	}
278	
279	// ---------------------------------------------------------------------------
280	// 5. Fr facts must only use a fresh- or a msg-variable
281	// ---------------------------------------------------------------------------
282	pub fn fr_facts(thy: &Theory) -> Vec<WfError> {
283	    let mut entries: Vec<String> = Vec::new();
284	    for r in protocol_rules(thy) {
285	        for facts in [&r.premises, &r.conclusions] {
286	            for f in facts {
287	                if f.name != "Fr" {
288	                    continue;
289	                }
290	                let ok = f.args.len() == 1
291	                    && matches!(
292	                        &f.args[0],
293	                        Term::Var(v) if matches!(v.sort, SortHint::Fresh | SortHint::Msg | SortHint::Untagged)
294	                    );
295	                if !ok {
296	                    entries.push(format!("  rule `{}' fact: {}", r.name, pp_fact(f)));
297	                }
298	            }
299	        }
300	    }
301	    if entries.is_empty() {
302	        vec![]
303	    } else {
304	        vec![WfError::new(T_FR, entries.join("\n  \n"))]
305	    }
306	}
307	
308	// ---------------------------------------------------------------------------
309	// 6. Special facts (disallowed I/O facts in wrong position)
310	// ---------------------------------------------------------------------------
311	pub fn special_facts(thy: &Theory) -> Vec<WfError> {
312	    let mut entries: Vec<String> = Vec::new();
313	    for r in protocol_rules(thy) {
314	        // Premise side: `Out` is disallowed.
315	        let lhs: Vec<String> = r
316	            .premises
317	            .iter()
318	            .filter(|f| f.name == "Out")
319	            .map(|f| pp_fact(f))
320	            .collect();
321	        if !lhs.is_empty() {
322	            entries.push(format!(
323	                "  rule `{}' uses disallowed facts on left-hand-side:\n    {}",
324	                r.name,
325	                lhs.join(", ")
326	            ));
327	        }
328	        // Conclusion side: `In` and `Fr` are disallowed.
329	        let rhs: Vec<String> = r
330	            .conclusions
331	            .iter()
332	            .filter(|f| f.name == "In" || f.name == "Fr")
333	            .map(|f| pp_fact(f))
334	            .collect();
335	        if !rhs.is_empty() {
336	            entries.push(format!(
337	                "  rule `{}' uses disallowed facts on right-hand-side:\n    {}",
338	                r.name,
339	                rhs.join(", ")
340	            ));
341	        }
342	    }
343	    if entries.is_empty() {
344	        vec![]
345	    } else {
346	        vec![WfError::new(T_SPECIAL, entries.join("\n  \n"))]
347	    }
348	}
349	
350	// ---------------------------------------------------------------------------
351	// 7 & 8. Fact arity / multiplicity issues
352	// ---------------------------------------------------------------------------
353	
354	struct FactUse {
355	    rule: String,
356	    arity: usize,
357	    persistent: bool,
358	    pp: String,
359	}
360	
361	/// Gather every fact occurrence in protocol rules (name -> uses), in source
362	/// order.
363	fn gather_fact_uses(thy: &Theory) -> Vec<(String, Vec<FactUse>)> {
364	    let mut map: Vec<(String, Vec<FactUse>)> = Vec::new();
365	    for r in protocol_rules(thy) {
366	        for facts in [&r.premises, &r.actions, &r.conclusions] {
367	            for f in facts {
368	                let entry = FactUse {
369	                    rule: r.name.clone(),
370	                    arity: f.args.len(),
371	                    persistent: f.persistent,
372	                    pp: pp_fact(f),
373	                };
374	                match map.iter_mut().find(|(n, _)| *n == f.name) {
375	                    Some((_, uses)) => uses.push(entry),
376	                    None => map.push((f.name.clone(), vec![entry])),
377	                }
378	            }
379	        }
380	    }
381	    map
382	}
383	
384	fn render_fact_blocks(conflicts: &[(String, Vec<String>)], intro1: &str, intro2: &str) -> String {
385	    // conflicts: (lowercased fact name, item lines) already ordered.
386	    let mut body = format!("{}\n{}\n  ", intro1, intro2);
387	    for (i, (lname, items)) in conflicts.iter().enumerate() {
388	        let block = format!("  Fact `{}':\n\n{}\n  ", lname, items.join("\n    \n"));
389	        if i == 0 {
390	            body.push_str("\n\n");
391	        } else {
392	            body.push('\n');
393	        }
394	        body.push_str(&block);
395	    }
396	    body
397	}
