399	pub fn fact_arity(thy: &Theory) -> Vec<WfError> {
400	    let uses = gather_fact_uses(thy);
401	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
402	    for (name, us) in &uses {
403	        let arities: std::collections::BTreeSet<usize> = us.iter().map(|u| u.arity).collect();
404	        if arities.len() < 2 {
405	            continue;
406	        }
407	        // one item per distinct (rule, arity), first pp kept, source order.
408	        let mut seen: Vec<(String, usize)> = Vec::new();
409	        let mut items: Vec<String> = Vec::new();
410	        for u in us {
411	            let k = (u.rule.clone(), u.arity);
412	            if seen.contains(&k) {
413	                continue;
414	            }
415	            seen.push(k);
416	            let n = items.len() + 1;
417	            items.push(format!(
418	                "    {}. Rule `{}', arity {}\n         {}",
419	                n, u.rule, u.arity, u.pp
420	            ));
421	        }
422	        conflicts.push((name.to_lowercase(), items));
423	    }
424	    if conflicts.is_empty() {
425	        return vec![];
426	    }
427	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
428	    let msg = render_fact_blocks(
429	        &conflicts,
430	        "Same fact is used with different arities, i.e., Fact('A','B') is different from Fact('A'). ",
431	        "Check the arguments of your facts.",
432	    );
433	    vec![WfError::new(T_ARITY, msg)]
434	}
