477	#[derive(Clone)]
478	struct FactId {
479	    name: String,
480	    arity: usize,
481	    persistent: bool,
482	    rule: String,
483	}
484	
485	impl FactId {
486	    fn ident(&self) -> (String, usize, bool) {
487	        (self.name.clone(), self.arity, self.persistent)
488	    }
489	    fn render(&self) -> String {
490	        format!(
491	            "in rule \"{}\":  factName `{}' arity: {} multiplicity: {}",
492	            self.rule,
493	            self.name,
494	            self.arity,
495	            if self.persistent { "Persistent" } else { "Linear" }
496	        )
497	    }
