500	pub fn fact_lhs_occur_no_rhs(thy: &Theory) -> Vec<WfError> {
501	    let mut lhs: Vec<FactId> = Vec::new();
502	    let mut rhs: Vec<FactId> = Vec::new();
503	    for r in protocol_rules(thy) {
504	        for f in &r.premises {
505	            if is_builtin_factname(&f.name) {
506	                continue;
507	            }
508	            lhs.push(FactId {
509	                name: f.name.clone(),
510	                arity: f.args.len(),
511	                persistent: f.persistent,
512	                rule: r.name.clone(),
513	            });
514	        }
515	        for f in &r.conclusions {
516	            if is_builtin_factname(&f.name) {
517	                continue;
518	            }
519	            rhs.push(FactId {
520	                name: f.name.clone(),
521	                arity: f.args.len(),
522	                persistent: f.persistent,
523	                rule: r.name.clone(),
524	            });
525	        }
526	    }
527	    let rhs_idents: std::collections::HashSet<(String, usize, bool)> =
528	        rhs.iter().map(|f| f.ident()).collect();
529	
530	    // LHS-only identities, first occurrence, in source order.
531	    let mut seen: Vec<(String, usize, bool)> = Vec::new();
532	    let mut items: Vec<String> = Vec::new();
533	    for f in &lhs {
534	        if rhs_idents.contains(&f.ident()) || seen.contains(&f.ident()) {
535	            continue;
536	        }
537	        seen.push(f.ident());
538	        let n = items.len() + 1;
539	        let mut line = format!("  {}. {}", n, f.render());
540	        if let Some(sugg) = nearest_rhs(&f.name, &rhs) {
541	            line.push_str(&format!(". Perhaps you want to use the fact {}", sugg.render()));
542	        }
543	        items.push(line);
544	    }
545	    if items.is_empty() {
546	        vec![]
547	    } else {
548	        vec![WfError::new(T_LHSRHS, items.join("\n  \n"))]
549	    }
550	}
