552	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
553	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
554	    let mut best: Option<(usize, &FactId)> = None;
555	    for f in rhs {
556	        let d = edit_distance(name, &f.name);
557	        match best {
558	            Some((bd, _)) if d >= bd => {}
559	            _ => best = Some((d, f)),
560	        }
561	    }
562	    match best {
563	        Some((d, f)) if d <= 3 => Some(f),
564	        _ => None,
565	    }
566	}
567	
568	fn edit_distance(a: &str, b: &str) -> usize {
569	    let a: Vec<char> = a.chars().collect();
570	    let b: Vec<char> = b.chars().collect();
571	    let mut prev: Vec<usize> = (0..=b.len()).collect();
572	    let mut cur = vec![0usize; b.len() + 1];
573	    for i in 1..=a.len() {
574	        cur[0] = i;
575	        for j in 1..=b.len() {
576	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
577	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
578	        }
579	        std::mem::swap(&mut prev, &mut cur);
580	    }
581	    prev[b.len()]
582	}
