657	// 10. Formula terms (free variables in lemma / restriction formulas)
658	// ---------------------------------------------------------------------------
659	
660	const FORMULA_TERMS_HELP: &str = "  The only allowed terms are public constants and bound node and\n  message variables. If you encounter free message variables, then\n  you might have forgotten a #-prefix. Sort prefixes can only be\n  dropped where this is unambiguous. Moreover, reducible function\n  symbols are disallowed.";
661	
662	fn free_vars_formula(f: &Formula, bound: &mut Vec<(String, i32)>, out: &mut Vec<VarSpec>) {
663	    match f {
664	        Formula::False | Formula::True => {}
665	        Formula::Atom(a) => {
666	            let mut vs = Vec::new();
667	            atom_vars(a, &mut vs);
668	            for v in vs {
669	                let k = (v.name.clone(), sort_rank(v.sort));
670	                if !bound.contains(&k) {
671	                    out.push(v);
672	                }
673	            }
674	        }
675	        Formula::Not(g) => free_vars_formula(g, bound, out),
676	        Formula::And(a, b)
677	        | Formula::Or(a, b)
678	        | Formula::Implies(a, b)
679	        | Formula::Iff(a, b) => {
680	            free_vars_formula(a, bound, out);
681	            free_vars_formula(b, bound, out);
682	        }
683	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
684	            let added: Vec<(String, i32)> =
685	                vs.iter().map(|v| (v.name.clone(), sort_rank(v.sort))).collect();
686	            let n = added.len();
687	            bound.extend(added);
688	            free_vars_formula(g, bound, out);
689	            for _ in 0..n {
690	                bound.pop();
691	            }
692	        }
693	    }
694	}
695	
696	fn atom_vars(a: &Atom, out: &mut Vec<VarSpec>) {
697	    match a {
698	        Atom::Eq(x, y)
699	        | Atom::Less(x, y)
700	        | Atom::LessMset(x, y)
701	        | Atom::Subterm(x, y) => {
702	            collect_term_vars(x, out);
703	            collect_term_vars(y, out);
704	        }
705	        Atom::Action(f, t) => {
706	            collect_fact_vars(f, out);
707	            collect_term_vars(t, out);
708	        }
709	        Atom::Last(t) => collect_term_vars(t, out),
710	        Atom::Pred(f) => collect_fact_vars(f, out),
711	    }
712	}
