714	fn formula_terms_entry(entity: &str, name: &str, free: &[VarSpec]) -> String {
715	    let terms: Vec<String> = free.iter().map(|v| format!("`Free {}'", pp_var(v))).collect();
716	    let head = if terms.len() == 1 {
717	        format!(
718	            "  {} `{}' uses terms of the wrong form: {}",
719	            entity, name, terms[0]
720	        )
721	    } else {
722	        format!(
723	            "  {} `{}' uses terms of the wrong form:\n    {}",
724	            entity,
725	            name,
726	            terms.join(", ")
727	        )
728	    };
729	    format!("{}\n  \n{}", head, FORMULA_TERMS_HELP)
730	}
731	
732	pub fn formula_terms(thy: &Theory) -> Vec<WfError> {
733	    let mut entries: Vec<String> = Vec::new();
734	    for it in &thy.items {
735	        let (entity, name, formula) = match it {
736	            TheoryItem::Lemma(l) => ("Lemma", &l.name, &l.formula),
737	            TheoryItem::Restriction(r) | TheoryItem::LegacyAxiom(r) => {
738	                ("Restriction", &r.name, &r.formula)
739	            }
740	            _ => continue,
741	        };
742	        let mut bound = Vec::new();
743	        let mut free = Vec::new();
744	        free_vars_formula(formula, &mut bound, &mut free);
745	        let free = dedup_vars(free);
746	        if !free.is_empty() {
747	            entries.push(formula_terms_entry(entity, name, &free));
748	        }
749	    }
750	    if entries.is_empty() {
751	        vec![]
752	    } else {
753	        vec![WfError::new(T_FORMULA_TERMS, entries.join("\n"))]
754	    }
755	}
