758	// 11. Formula guardedness (best-effort; single-line formula printer)
759	// ---------------------------------------------------------------------------
760	
761	pub fn formula_guardedness(thy: &Theory) -> Vec<WfError> {
762	    let mut entries: Vec<String> = Vec::new();
763	    for it in &thy.items {
764	        let (name, formula) = match it {
765	            TheoryItem::Lemma(l) => (&l.name, &l.formula),
766	            _ => continue,
767	        };
768	        if let Some((unguarded, sub)) = find_unguarded(formula) {
769	            let vars: Vec<String> = unguarded.iter().map(|v| format!("'{}'", pp_var(v))).collect();
770	            let pp_sub = crate::formula::pp_formula(&sub);
771	            let pp_whole = crate::formula::pp_formula(formula);
772	            entries.push(format!(
773	                "  Lemma `{}' cannot be converted to a guarded formula:\n    unguarded variable(s) {} in the subformula\n      \"{}\"\n    in the formula\n      \"{}\"",
774	                name,
775	                vars.join(", "),
776	                pp_sub,
777	                pp_whole
778	            ));
779	        }
780	    }
781	    if entries.is_empty() {
782	        vec![]
783	    } else {
784	        vec![WfError::new(T_GUARD, entries.join("\n"))]
785	    }
786	}
