788	/// Variables appearing in any Action or Pred atom anywhere in `f` (the guard
789	/// positions). Used as a permissive over-approximation of "guarded".
790	fn guard_vars(f: &Formula, out: &mut Vec<VarSpec>) {
791	    match f {
792	        Formula::Atom(Atom::Action(fact, t)) => {
793	            collect_fact_vars(fact, out);
794	            collect_term_vars(t, out);
795	        }
796	        Formula::Atom(Atom::Pred(fact)) => collect_fact_vars(fact, out),
797	        Formula::Atom(_) | Formula::True | Formula::False => {}
798	        Formula::Not(g) => guard_vars(g, out),
799	        Formula::And(a, b)
800	        | Formula::Or(a, b)
801	        | Formula::Implies(a, b)
802	        | Formula::Iff(a, b) => {
803	            guard_vars(a, out);
804	            guard_vars(b, out);
805	        }
806	        Formula::Forall(_, g) | Formula::Exists(_, g) => guard_vars(g, out),
807	    }
808	}
809	
810	/// Returns the first quantifier whose bound variables are not all guarded,
811	/// together with that subformula.
812	fn find_unguarded(f: &Formula) -> Option<(Vec<VarSpec>, Formula)> {
813	    match f {
814	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
815	            let mut gv = Vec::new();
816	            guard_vars(g, &mut gv);
817	            let gset: std::collections::HashSet<(String, i32)> =
818	                gv.iter().map(|v| (v.name.clone(), sort_rank(v.sort))).collect();
819	            let unguarded: Vec<VarSpec> = vs
820	                .iter()
821	                .filter(|v| !gset.contains(&(v.name.clone(), sort_rank(v.sort))))
822	                .cloned()
823	                .collect();
824	            if !unguarded.is_empty() {
825	                return Some((unguarded, f.clone()));
826	            }
827	            find_unguarded(g)
828	        }
829	        Formula::Not(g) => find_unguarded(g),
830	        Formula::And(a, b)
831	        | Formula::Or(a, b)
832	        | Formula::Implies(a, b)
833	        | Formula::Iff(a, b) => find_unguarded(a).or_else(|| find_unguarded(b)),
834	        _ => None,
835	    }
836	}
