842	pub fn nat_sorts(thy: &Theory) -> Vec<WfError> {
843	    let mut entries: Vec<String> = Vec::new();
844	    for r in protocol_rules(thy) {
845	        for facts in [&r.premises, &r.actions, &r.conclusions] {
846	            for f in facts {
847	                for a in &f.args {
848	                    collect_nat_issues(a, &mut entries);
849	                }
850	            }
851	        }
852	    }
853	    if entries.is_empty() {
854	        vec![]
855	    } else {
