859	
860	fn collect_nat_issues(t: &Term, out: &mut Vec<String>) {
861	    if let Term::BinOp(BinOp::NatPlus, _, _) = t {
862	        let term_pp = pp_term(t);
863	        let mut vs = Vec::new();
864	        collect_term_vars(t, &mut vs);
865	        for v in vs {
866	            if v.sort != SortHint::Nat {
867	                let entry = format!("  {} in term {} must be of sort nat", pp_var(&v), term_pp);
868	                if !out.contains(&entry) {
869	                    out.push(entry);
870	                }
871	            }
872	        }
873	    }
874	    // recurse
875	    match t {
876	        Term::App(_, args) | Term::Pair(args) => {
877	            for a in args {
878	                collect_nat_issues(a, out);
879	            }
880	        }
881	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
882	            collect_nat_issues(a, out);
883	            collect_nat_issues(b, out);
884	        }
885	        Term::PatMatch(inner) => collect_nat_issues(inner, out),
886	        _ => {}
887	    }
888	}
