893	
894	pub fn subterm_convergence(thy: &Theory) -> Vec<WfError> {
895	    let mut bad: Vec<String> = Vec::new();
896	    for it in &thy.items {
897	        if let TheoryItem::Equations { convergent, eqs } = it {
898	            if *convergent {
899	                continue; // user asserted convergence
900	            }
901	            for eq in eqs {
902	                if !is_subterm(&eq.rhs, &eq.lhs) {
903	                    bad.push(format!("    {} = {}", pp_term(&eq.lhs), pp_term(&eq.rhs)));
904	                }
905	            }
906	        }
907	    }
908	    if bad.is_empty() {
909	        return vec![];
910	    }
911	    let intro = "  User-defined equations must be convergent and have the finite variant property. The following equations are not subterm convergent. If you are sure that the set of equations is nevertheless convergent and has the finite variant property, you can ignore this warning and continue ";
912	    let manual = " For more information, please refer to the manual : https://tamarin-prover.com/manual/master/book/010_modeling-issues.html ";
913	    let msg = format!("{}\n\n{}\n   \n{}", intro, bad.join("\n"), manual);
914	    vec![WfError::new(T_SUBTERM, msg)]
915	}
