917	/// Structural subterm test: does `small` occur as a subterm of `big`?
918	fn is_subterm(small: &Term, big: &Term) -> bool {
919	    if small == big {
920	        return true;
921	    }
922	    match big {
923	        Term::App(_, args) | Term::Pair(args) => args.iter().any(|a| is_subterm(small, a)),
924	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
925	            is_subterm(small, a) || is_subterm(small, b)
926	        }
927	        Term::PatMatch(inner) => is_subterm(small, inner),
928	        _ => false,
929	    }
930	}
