35	/// Run every check in the oracle's report order.
36	pub fn check_theory(thy: &Theory) -> WfReport {
37	    let mut report: WfReport = Vec::new();
38	    // Base pipeline (public names inserted afterwards at its anchor point).
39	    report.extend(checks::unbound_variables(thy)); // 1
40	    report.extend(checks::mismatching_sorts(thy)); // 3
41	    report.extend(checks::reserved_names(thy)); // 4
42	    report.extend(checks::fr_facts(thy)); // 5
43	    report.extend(checks::special_facts(thy)); // 6
44	    report.extend(checks::fact_arity(thy)); // 7
45	    report.extend(checks::fact_multiplicity(thy)); // 8
46	    report.extend(checks::fact_lhs_occur_no_rhs(thy)); // 9
47	    report.extend(checks::formula_terms(thy)); // 10
48	    report.extend(checks::formula_guardedness(thy)); // 11
49	    report.extend(checks::nat_sorts(thy)); // 12
50	    report.extend(checks::subterm_convergence(thy)); // 13
51	
52	    let pn = checks::public_names_report(thy); // 2
53	    let anchors = after_public_names_topics();
54	    insert_wf_before(&mut report, pn, &anchors);
55	    report
56	}
