49	/// A wellformedness diagnostic. `topic` matches exactly the underlined
50	/// header string Tamarin emits (e.g. `"Reserved names"`,
51	/// `"Fact arity issues"`).
52	#[derive(Debug, Clone, PartialEq, Eq, Ord, PartialOrd)]
53	pub struct WfError {
