76	/// Canonical HS wellformedness check-order (Wellformedness.hs check list).
77	/// Each ordered-splice call site (in the batch `run.rs` and web `theory_io.rs`
78	/// load pipelines) passes a SUFFIX of this list as its `anchors`: since
79	/// [`insert_wf_before`] only tests membership, a suffix contains exactly the
80	/// topics that sort AFTER the check being inserted.  One source of truth
81	/// avoids several in-sync literal lists that would silently mis-order a single
82	/// report on a typo.
83	pub const WF_TOPIC_ORDER: &[&str] = &[
84	    "Reserved names",
85	    "Special facts",
86	    "Fr facts must only use a fresh- or a msg-variable",
87	    "Fact arity issues",
88	    "Fact multiplicity issues",
89	    "Fact capitalization issues",
90	    "Facts occur in the left-hand-side but not in any right-hand-side ",
91	    "Unbound variables",
92	    "Formula terms",
93	    " Formula guardedness",
94	    "Lemma annotations",
95	    "Multiplication restriction of rules",
96	    "Nat Sorts",
97	    "Subterm Convergence Warning",
98	    "Message Derivation Checks",
99	    "Derivation Checks",
100	];
101	
102	// First `WF_TOPIC_ORDER` index whose topic sorts after each splicing check.
103	pub const WF_AFTER_VARIANTS: usize = 0; // ruleVariantsReport → before factReports
104	pub const WF_AFTER_FACT_LHS: usize = 8; // "Formula terms"
105	pub const WF_AFTER_CHECK_TERMS: usize = 9; // " Formula guardedness"
106	pub const WF_AFTER_CHECK_GUARDED: usize = 10; // "Lemma annotations"
107	
108	/// Splice `errors` into `report` immediately before the first existing entry
109	/// whose `topic` is one of `anchors` (its HS check-order position), or at the
110	/// end if none match, preserving the relative order of both the existing tail
111	/// and the inserted errors.  Shared by the batch (`run.rs`) and web
112	/// (`theory_io.rs`) ordered-splice call sites — checkTerms / checkGuarded /
113	/// SAPIC lhs-rhs / ruleVariants — which differ only in their `anchors` slice
114	/// and the source of `errors`.  No-op when `errors` is empty.
115	pub fn insert_wf_before(report: &mut Vec<WfError>, errors: Vec<WfError>, anchors: &[&str]) {
116	    if errors.is_empty() {
117	        return;
118	    }
119	    let insert_before = report
120	        .iter()
121	        .position(|e| anchors.contains(&e.topic.as_str()))
122	        .unwrap_or(report.len());
123	    let tail = report.split_off(insert_before);
124	    report.extend(errors);
125	    report.extend(tail);
126	}
127	
128	/// Anchor list for the SAPIC `publicNamesReport` splice (HS check index 4):
129	/// the variable-sorts topic, then every [`WF_TOPIC_ORDER`] topic EXCEPT
130	/// "Unbound variables" (HS `unboundReport` runs BEFORE `publicNames`, so its
131	/// entries must not act as a boundary).  publicNames therefore splices before
132	/// the first entry from a later check.
133	pub fn after_public_names_topics() -> Vec<&'static str> {
134	    std::iter::once("Variable with mismatching sorts or capitalization")
135	        .chain(
136	            WF_TOPIC_ORDER
137	                .iter()
138	                .copied()
139	                .filter(|t| *t != "Unbound variables"),
140	        )
141	        .collect()
142	}
