144	/// Run every wellformedness check against `thy`. Topics from the result
145	/// can be compared directly against `tamarin-prover`'s output.
146	pub fn check_theory(thy: &Theory) -> WfReport {
147	    // Mirrors HS `Theory.Tools.Wellformedness.checkWellformedness`
148	    // (Wellformedness.hs:1270-1287) and, for diff theories,
149	    // `checkWellformednessDiff` (1248-1265), in HS check order: unbound,
150	    // freshNames, publicNames, ruleSorts (variable_sort_clashes),
151	    // factReports, [leftRightRule (diff only)], formulaReports,
152	    // lemmaAttribute, multRestricted, natWellSorted, subtermConvergence,
153	    // then message-derivation.  `leftRightRuleReportDiff` is placed AFTER
154	    // the factReports group and the ruleSorts check, matching the diff
155	    // order at Wellformedness.hs:1256-1261.
156	    let mut report = Vec::new();
157	    report.extend(unbound_report(thy));
158	    report.extend(fresh_names_report(thy));
159	    report.extend(public_names_report(thy));
160	    // HS `ruleSortsReport` (sortsClashCheck) runs HERE — after publicNamesReport
161	    // and BEFORE factReports (Wellformedness.hs:1275/1256).  It is ported as
162	    // `variable_sort_clashes` ("Variable with mismatching sorts or
163	    // capitalization").
164	    report.extend(variable_sort_clashes(thy));
165	    // ruleVariantsReport — not ported (needs MaudeHandle + variant solver).
166	    // factReports group:
167	    report.extend(reserved_report(thy));
168	    report.extend(reserved_fact_name_rules(thy));
169	    report.extend(reserved_prefix_report(thy));
170	    report.extend(fresh_fact_arguments(thy));
171	    report.extend(special_facts_usage(thy));
172	    report.extend(fact_usage(thy));
173	    report.extend(fact_lhs_occur_no_rhs(thy));
174	    // leftRightRuleReportDiff (diff only) — placed AFTER factReports and
175	    // ruleSorts, BEFORE formulaReports, matching HS `checkWellformednessDiff`
176	    // order (Wellformedness.hs:1259).  (ruleVariantsReportDiff sits between
177	    // factReports and leftRightRule in HS but is unported, so it does not
178	    // affect placement.)
179	    report.extend(left_right_rule_report(thy));
180	    // formulaReports group:
181	    // checkQuantifiers / checkGuarded — partial via formula_free_var_report.
182	    // lemmaAttributeReport, multRestrictedReport, natWellSortedReport:
183	    report.extend(lemma_attribute_report(thy));
184	    report.extend(mult_restricted_report(thy));
185	    report.extend(nat_well_sorted_report(thy));
186	    // checkEquationsSubtermConvergence:
187	    report.extend(subterm_convergence_report(thy));
188	    // Message Derivation Checks (HS: TheoryLoader.hs:172-176 +
189	    // MessageDerivationChecks.hs:35).  HS's check is dynamic
190	    // (per-variable prover invocation, --derivcheck-timeout default 5s);
191	    // we run a static intersection that catches the same variables for
192	    // the common case.  See `message_derivation_report` docstring.
193	    report.extend(message_derivation_report(thy));
194	    report
195	}
