202	// =============================================================================
203	// Check that CLI --prove/--lemma arguments name actual lemmas in the theory
204	// =============================================================================
205	
206	/// Port of HS `checkIfLemmasInTheory` (Wellformedness.hs:1156-1171).
207	///
208	/// HS threads `_lemmasToProve` through the theory's `Options` record.
209	/// In the Rust port the CLI args are not embedded in the parser AST,
210	/// so we take them as a separate parameter.
211	///
212	/// Semantics (mirror of `findNotProvedLemmas` / `lemmaChecker`):
213	///   - An empty `lemma_names` slice (no `--prove` / `--lemma` flag)
214	///     means "prove all" → skip the check.
215	///   - A list that is exactly `[""]` (bare `--prove` with no value)
216	///     also means "all" → skip.
217	///   - Otherwise: for each name in `lemma_names`, it "corresponds" if
218	///     • there is a theory lemma whose name equals it exactly, OR
219	///     • the name ends with `*` and its prefix is a prefix of at least
220	///     one theory-lemma name.
221	///     Names that don't correspond are collected; if any exist the WF
222	///     check fires.
223	pub fn check_if_lemmas_in_theory(lemma_names: &[String], thy: &Theory) -> WfReport {
224	    // HS: `| lemmaArgsNames == [[]] = []`  (Wellformedness.hs:1158)
225	    // HS stores lemmaArgsNames as [String]; [[]] is [""] (a list
226	    // containing exactly one empty string), which means bare `--prove`
227	    // with no argument value.  Skip the check ONLY in that case.
228	    //
229	    // When lemma_names is EMPTY (no --prove at all) → also skip.
230	    // When lemma_names has MIXED entries (e.g. `--prove --lemma=BadX`
231	    // → ["", "BadX"]) the HS condition fails so the check DOES run —
232	    // the empty string is reported as "not found" too (faithfulness
233	    // requires we keep empty strings in the probe list).
234	    if lemma_names.is_empty() {
235	        return Vec::new();
236	    }
237	    // Exactly one entry and it is empty → bare `--prove` → skip.
238	    if lemma_names == [""] {
239	        return Vec::new();
240	    }
241	    // Collect non-empty names for the "matches any lemma" test;
242	    // empty strings are kept in the fold below since HS does NOT
243	    // filter them (they trivially fail argFilter).
244	    let all_names: Vec<&str> = lemma_names.iter().map(|s| s.as_str()).collect();
245	
246	    let theory_lemma_names: Vec<&str> = theory_lemmas(thy)
247	        .into_iter()
248	        .map(|l| l.name.as_str())
249	        .collect();
250	
251	    // HS `findNotProvedLemmas` (Wellformedness.hs:1141) is a `foldl`
252	    // that PREPENDS mismatches.  HS's Arguments list is built with
253	    // `addArg` which prepends each CLI flag, so the stored arg list is
254	    // in REVERSE CLI order.  `findArg` returns them in that reversed
255	    // order; `foldl`-prepend of a reversed list re-reverses → the final
256	    // `notProvedLemmas` is in ORIGINAL CLI order.
257	    //
258	    // RS's `lemma_names` is already in CLI order (no prepend in
259	    // `parse_args`), so a simple forward-iterate-and-push yields the
260	    // same result as the double-reversed HS fold.
261	    let mut not_proved: Vec<&str> = Vec::new();
262	    for name in all_names.iter() {
263	        if !arg_matches_any_lemma(name, &theory_lemma_names) {
264	            not_proved.push(name);
265	        }
266	    }
267	
268	    if not_proved.is_empty() {
269	        return Vec::new();
270	    }
271	
272	    // HS topic: `underlineTopic "Check presence of the --prove/--lemma
273	    // arguments in theory"` (Wellformedness.hs:1169).
274	    let topic_str = "Check presence of the --prove/--lemma arguments in theory";
275	    // HS body: `vcat [text $ "--> '" ++ intercalate "', '" notProvedLemmas
276	    //   ++ "'" ++ " from arguments do(es) not correspond ..."]`
277	    // Rendered via `prettyWfErrorReport` → `nest 2`:
278	    //   "<topic>\n<===>\n\n  --> '<names>' from arguments ...\n"
279	    let names_str = not_proved.join("', '");
280	    let body_line = format!(
281	        "--> '{}' from arguments do(es) not correspond to a specified lemma in the theory ",
282	        names_str,
283	    );
284	
285	    // Build the message in the same shape that format_wf_block expects:
286	    // the topic header (underlineTopic output) followed by a blank line,
287	    // followed by the 2-space-indented body line.
288	    // HS prettyWfErrorReport: `text topic $-$ (nest 2 . vcat ... $ map snd errs)`
289	    // `text topic` renders the underlineTopic string (title\n====\n),
290	    // `$-$` appends one more newline, so we get title\n====\n\n<body>.
291	    let mut msg = String::new();
292	    msg.push_str(&underline_topic(topic_str));
293	    msg.push('\n');                   // blank line between header and body
294	    msg.push_str("  ");              // nest 2
295	    msg.push_str(&body_line);
296	    msg.push('\n');
297	
298	    vec![WfError::new(topic_str, msg)]
299	}
300	
301	/// True if `arg` "corresponds" to at least one lemma name in
302	/// `theory_lemmas`.  Mirrors HS `lemmaChecker`:
303	///   - suffix `*` → prefix match on the lemma name (no `*` in result)
304	///   - otherwise  → exact equality
305	fn arg_matches_any_lemma(arg: &str, theory_lemmas: &[&str]) -> bool {
306	    if let Some(prefix) = arg.strip_suffix('*') {
307	        theory_lemmas.iter().any(|n| n.starts_with(prefix))
308	    } else {
309	        theory_lemmas.contains(&arg)
310	    }
311	}
