317	fn theory_rules(thy: &Theory) -> Vec<&Rule> {
318	    let mut out = Vec::new();
319	    for it in &thy.items {
320	        match it {
321	            TheoryItem::Rule(r) => out.push(r),
322	            TheoryItem::IntrRule(r) => out.push(r),
323	            _ => {}
324	        }
325	    }
326	    out
327	}
328	
329	fn theory_lemmas(thy: &Theory) -> Vec<&Lemma> {
330	    thy.items.iter().filter_map(|it| match it {
331	        TheoryItem::Lemma(l) => Some(l),
332	        _ => None,
333	    }).collect()
334	}
