336	/// Iterate all facts in a rule (premises ∪ actions ∪ conclusions),
337	/// each paired with which side it appeared on. Callers currently discard
338	/// the side tag; it is retained for callers that need to distinguish sides.
339	// Intentionally retained: faithful HS port; no caller reads the tag yet.
340	#[allow(dead_code)]
341	#[derive(Clone, Copy, PartialEq, Eq)]
342	enum FactSide { Lhs, Acts, Rhs }
343	
344	fn rule_facts(r: &Rule) -> Vec<(FactSide, &Fact)> {
345	    let mut out = Vec::new();
346	    for f in &r.premises    { out.push((FactSide::Lhs, f)); }
347	    for f in &r.actions     { out.push((FactSide::Acts, f)); }
348	    for f in &r.conclusions { out.push((FactSide::Rhs, f)); }
349	    out
350	}
351	
352	/// Recursively collect every variable appearing in a term.
353	fn term_vars(t: &Term, out: &mut Vec<VarSpec>) {
354	    match t {
355	        Term::Var(v) => out.push(v.clone()),
356	        Term::App(_, args) => for a in args { term_vars(a, out); },
357	        Term::AlgApp(_, a, b) => { term_vars(a, out); term_vars(b, out); }
358	        Term::Pair(items) => for a in items { term_vars(a, out); },
359	        Term::Diff(a, b) => { term_vars(a, out); term_vars(b, out); }
360	        Term::BinOp(_, a, b) => { term_vars(a, out); term_vars(b, out); }
361	        Term::PatMatch(inner) => term_vars(inner, out),
362	        Term::PubLit(_) | Term::FreshLit(_) | Term::NatLit(_)
363	        | Term::Number(_) | Term::NumberOne | Term::NatOne | Term::DhNeutral => {}
364	    }
365	}
366	
367	fn fact_vars(f: &Fact) -> Vec<VarSpec> {
368	    let mut v = Vec::new();
369	    for a in &f.args { term_vars(a, &mut v); }
370	    v
371	}
372	
373	/// Collect every public-name literal (`'foo'`) and fresh-name literal
374	/// (`~'foo'`) within a term subtree.
375	#[derive(Clone, Copy, PartialEq, Eq)]
376	enum NameKind { Pub, Fresh }
377	
378	fn term_name_lits(t: &Term, out: &mut Vec<(NameKind, String)>) {
379	    match t {
380	        Term::PubLit(s) => out.push((NameKind::Pub, s.clone())),
381	        Term::FreshLit(s) => out.push((NameKind::Fresh, s.clone())),
382	        Term::App(_, args) => for a in args { term_name_lits(a, out); },
383	        Term::AlgApp(_, a, b) => { term_name_lits(a, out); term_name_lits(b, out); }
384	        Term::Pair(items) => for a in items { term_name_lits(a, out); },
385	        Term::Diff(a, b) => { term_name_lits(a, out); term_name_lits(b, out); }
386	        Term::BinOp(_, a, b) => { term_name_lits(a, out); term_name_lits(b, out); }
387	        Term::PatMatch(inner) => term_name_lits(inner, out),
388	        _ => {}
389	    }
390	}
391	
392	fn rule_terms(r: &Rule) -> impl Iterator<Item = &Term> {
393	    r.premises.iter().chain(&r.actions).chain(&r.conclusions)
394	        .flat_map(|f: &Fact| f.args.iter())
395	}
