397	/// Build an HS `underlineTopic` block: `"<title>\n<====>\n"` where the
398	/// underline matches the title length exactly (counting any trailing
399	/// space).  Mirrors `underlineTopic` in `Theory.Tools.Wellformedness`.
400	pub fn underline_topic(title: &str) -> String {
401	    let len = title.chars().count();
402	    let mut s = String::with_capacity(title.len() + len + 2);
403	    s.push_str(title);
404	    s.push('\n');
405	    for _ in 0..len { s.push('='); }
406	    s.push('\n');
407	    s
408	}
409	
410	/// Assemble a topic-grouped `WfReport` from pre-built body strings (empty
411	/// `bodies` yields an empty report).  `underline_topic` already ends the
412	/// `====` rule with a newline, so the extra `\n` is HS's `$-$` blank line
413	/// before the bodies; the bodies are joined by the `\n  \n` that HS's
414	/// `nest 2 (vcat (intersperse (text "") …))` renders a blank separator line
415	/// as (a 2-space `nest 2`'d `text ""`).  Each body already carries its own
416	/// 2-space `nest 2` indent.
417	fn grouped_topic_block(topic: &str, bodies: Vec<String>) -> WfReport {
418	    if bodies.is_empty() {
419	        return Vec::new();
420	    }
421	    let mut msg = underline_topic(topic);
422	    msg.push('\n');
423	    msg.push_str(&bodies.join("\n  \n"));
424	    vec![WfError::new(topic, msg)]
425	}
