427	/// HS `numbered'` index width: `nWidth = length (show n)` where `n` is the
428	/// number of items (PrettyPrint/Class.hs:257-258).  Each index is rendered as
429	/// `flushRight nWidth (show i)` — i.e. left-padded with spaces to this width —
430	/// so a 1-of-10+ list prints ` 1.`…`10.`.
431	fn numbered_index_width(count: usize) -> usize {
432	    count.to_string().len()
433	}
434	
435	/// Pretty-print a parser-AST fact in HS's `prettyLNFact` style:
436	/// `!Name( arg, arg, ... )` for persistent, `Name( arg, arg, ... )`
437	/// for linear.  Internal spaces match `nestShort'`.
438	fn pp_wf_fact(fa: &Fact) -> String {
439	    let mut s = String::new();
440	    if fa.persistent { s.push('!'); }
441	    s.push_str(&fa.name);
442	    s.push_str("( ");
443	    for (i, a) in fa.args.iter().enumerate() {
444	        if i > 0 { s.push_str(", "); }
445	        pp_wf_term(a, &mut s);
446	    }
447	    s.push_str(" )");
448	    s
449	}
450	
451	fn pp_wf_term(t: &Term, out: &mut String) {
452	    use Term::*;
453	    match t {
454	        Var(v) => {
455	            out.push_str(sort_prefix(&v.sort));
456	            out.push_str(&v.name);
457	            if v.idx > 0 { out.push('.'); out.push_str(&v.idx.to_string()); }
458	        }
459	        PubLit(s) => { out.push('\''); out.push_str(s); out.push('\''); }
460	        FreshLit(s) => { out.push_str("~'"); out.push_str(s); out.push('\''); }
461	        NatLit(s) => { out.push_str("%'"); out.push_str(s); out.push('\''); }
462	        Number(n) => out.push_str(&n.to_string()),
463	        // HS `prettyTerm` renders the nullary builtins via `text (BC.unpack f)`
464	        // except natOneSym ("%1"): oneSym → "one", dhNeutralSym → "DH_neutral"
465	        // (FunctionSymbols.hs:134,137,144; Term.hs:276,278).
466	        NumberOne => out.push_str("one"),
467	        NatOne => out.push_str("%1"),
468	        DhNeutral => out.push_str("DH_neutral"),
469	        Pair(items) => {
470	            out.push('<');
471	            for (i, it) in items.iter().enumerate() {
472	                if i > 0 { out.push_str(", "); }
473	                pp_wf_term(it, out);
474	            }
475	            out.push('>');
476	        }
477	        App(name, args) => {
478	            out.push_str(name);
479	            if !args.is_empty() {
480	                out.push('(');
481	                for (i, a) in args.iter().enumerate() {
482	                    if i > 0 { out.push_str(", "); }
483	                    pp_wf_term(a, out);
484	                }
485	                out.push(')');
486	            }
487	        }
488	        AlgApp(name, l, r) => {
489	            // HS canonicalises `aenc{m}pk` as `aenc(m, pk)`.
490	            out.push_str(name);
491	            out.push('(');
492	            pp_wf_term(l, out);
493	            out.push_str(", ");
494	            pp_wf_term(r, out);
495	            out.push(')');
496	        }
497	        Diff(l, r) => {
498	            out.push_str("diff(");
499	            pp_wf_term(l, out);
500	            out.push_str(", ");
501	            pp_wf_term(r, out);
502	            out.push(')');
503	        }
504	        BinOp(op, l, r) => {
505	            use crate::ast::BinOp as B;
506	            let sym = match op {
507	                B::Exp => "^",
508	                B::Mult => "*",
509	                B::Union => "++",
510	                B::Xor => "\u{2295}",
511	                B::NatPlus => "%+",
512	            };
513	            // HS builds AC operators (Mult/Union/Xor/NatPlus) via `fAppAC`,
514	            // which flattens the chain, sorts the operands (Ord LTerm), and
515	            // renders them parenthesised by `prettyTerm` (e.g. `(%x%+%1%+%1)`).
516	            // Exp is NOT AC: rendered binary, no surrounding parens.
517	            if matches!(op, B::Mult | B::Union | B::Xor | B::NatPlus) {
518	                let mut flat: Vec<&Term> = Vec::new();
519	                flatten_ac(*op, t, &mut flat);
520	                flat.sort_by(|a, b| cmp_wf_term(a, b));
521	                out.push('(');
522	                for (i, a) in flat.iter().enumerate() {
523	                    if i > 0 { out.push_str(sym); }
524	                    pp_wf_term(a, out);
525	                }
526	                out.push(')');
527	            } else {
528	                pp_wf_term(l, out);
529	                out.push_str(sym);
530	                pp_wf_term(r, out);
531	            }
532	        }
533	        PatMatch(inner) => { out.push('='); pp_wf_term(inner, out); }
534	    }
535	}
