537	/// Substitute every `let`-binding of a rule into its facts, mirroring HS,
538	/// whose rule parser inlines the `let` block before building the
539	/// `ProtoRuleE` (so wellformedness checks see fully-substituted facts).
540	///
541	/// HS `letBlock` (Parser/Let.hs:34) is `foldr1 compose` over singleton
542	/// substitutions — equivalent to applying each binding sequentially in
543	/// REVERSE binding order ("bottom-up").  Backward references expand;
544	/// FORWARD references survive as free variables.  Matches
545	/// `elaborate::apply_let_block`.
546	fn rule_facts_with_lets(r: &Rule) -> (Vec<Fact>, Vec<Fact>, Vec<Fact>) {
547	    let mut prems = r.premises.clone();
548	    let mut acts = r.actions.clone();
549	    let mut concs = r.conclusions.clone();
550	    for b in r.let_block.iter().rev() {
551	        for f in prems.iter_mut() { subst_let_fact(f, &b.var, &b.value); }
552	        for f in acts.iter_mut()  { subst_let_fact(f, &b.var, &b.value); }
553	        for f in concs.iter_mut() { subst_let_fact(f, &b.var, &b.value); }
554	    }
555	    (prems, acts, concs)
556	}
557	
558	fn subst_let_fact(f: &mut Fact, key: &Term, val: &Term) {
559	    for a in f.args.iter_mut() {
560	        *a = subst_let_term(a, key, val);
561	    }
562	}
563	
564	fn subst_let_term(t: &Term, key: &Term, val: &Term) -> Term {
565	    if t == key { return val.clone(); }
566	    use Term::*;
567	    match t {
568	        App(name, args) =>
569	            App(name.clone(), args.iter().map(|a| subst_let_term(a, key, val)).collect()),
570	        AlgApp(name, a, b) =>
571	            AlgApp(name.clone(),
572	                Box::new(subst_let_term(a, key, val)),
573	                Box::new(subst_let_term(b, key, val))),
574	        Pair(args) =>
575	            Pair(args.iter().map(|a| subst_let_term(a, key, val)).collect()),
576	        Diff(a, b) =>
577	            Diff(Box::new(subst_let_term(a, key, val)),
578	                 Box::new(subst_let_term(b, key, val))),
579	        BinOp(op, a, b) =>
580	            BinOp(*op, Box::new(subst_let_term(a, key, val)),
581	                       Box::new(subst_let_term(b, key, val))),
582	        PatMatch(a) => PatMatch(Box::new(subst_let_term(a, key, val))),
583	        Var(_) | PubLit(_) | FreshLit(_) | NatLit(_) | Number(_)
584	        | NumberOne | NatOne | DhNeutral => t.clone(),
585	    }
586	}
587	
588	/// Flatten an AC `BinOp` chain (same operator) into its operand list,
589	/// mirroring HS `fAppAC`'s flatten-then-sort (Term/Term/Raw.hs:118-128).
590	fn flatten_ac<'a>(op: crate::ast::BinOp, t: &'a Term, out: &mut Vec<&'a Term>) {
591	    match t {
592	        Term::BinOp(inner, l, r) if *inner == op => {
593	            flatten_ac(op, l, out);
594	            flatten_ac(op, r, out);
595	        }
596	        _ => out.push(t),
597	    }
598	}
