600	/// HS `Ord LTerm` for the subset of parser terms we render here.
601	///
602	/// HS-faithful class order (Term/Term/Raw.hs:72-74, VTerm.hs:56-57):
603	/// `LIT _ < FAPP _ _`, and within `LIT`, `Con < Var`, with constant Names
604	/// ordered by NameTag (Fresh < Pub < Nat, LTerm.hs:215).  The nullary
605	/// builtins `1`/`%1`/`DH-neutral` are `fAppNoEq … []` so they live in the
606	/// FAPP class.  Within a class we fall back to a structural tie-break that
607	/// is enough for the AC operand lists that arise here.
608	fn cmp_wf_term(a: &Term, b: &Term) -> std::cmp::Ordering {
609	    fn class(t: &Term) -> (u8, u8) {
610	        use Term::*;
611	        match t {
612	            // LIT (Con name): constants, by NameTag Fresh<Pub<Nat.
613	            FreshLit(_) => (0, 0),
614	            PubLit(_) => (0, 1),
615	            NatLit(_) => (0, 2),
616	            Number(_) => (0, 3),
617	            // LIT (Var v): variables sort after all constants.
618	            Var(_) => (0, 4),
619	            // FAPP: nullary builtins are NoEq applications, not literals.
620	            NumberOne => (1, 0),
621	            NatOne => (1, 1),
622	            DhNeutral => (1, 2),
623	            App(..) => (1, 3),
624	            AlgApp(..) => (1, 4),
625	            Pair(_) => (1, 5),
626	            Diff(..) => (1, 6),
627	            BinOp(..) => (1, 7),
628	            PatMatch(_) => (1, 8),
629	        }
630	    }
631	    let (ca, sa) = class(a);
632	    let (cb, sb) = class(b);
633	    if ca != cb { return ca.cmp(&cb); }
634	    if sa != sb { return sa.cmp(&sb); }
635	    use Term::*;
636	    // `class` maps every variant to a unique `(class, subclass)`, so the two
637	    // early returns above guarantee `a` and `b` are the same variant and each
638	    // `let … else` binding of `b` is infallible.  Match `a` exhaustively (no
639	    // wildcard) so a new `Term` variant forces an ordering decision here.  The
640	    // nullary FAPP builtins carry no payload, so same-variant pairs are `Equal`.
641	    match a {
642	        Var(v1) => {
643	            let Var(v2) = b else { unreachable!("term class matched Var") };
644	            // HS Ord LVar = (idx, sort, name) (LTerm.hs:521-523).
645	            v1.idx.cmp(&v2.idx)
646	                .then_with(|| sort_tag(&v1.sort).cmp(&sort_tag(&v2.sort)))
647	                .then_with(|| v1.name.cmp(&v2.name))
648	        }
649	        PubLit(s1) => {
650	            let PubLit(s2) = b else { unreachable!("term class matched PubLit") };
651	            s1.cmp(s2)
652	        }
653	        FreshLit(s1) => {
654	            let FreshLit(s2) = b else { unreachable!("term class matched FreshLit") };
655	            s1.cmp(s2)
656	        }
657	        NatLit(s1) => {
658	            let NatLit(s2) = b else { unreachable!("term class matched NatLit") };
659	            s1.cmp(s2)
660	        }
661	        Number(n1) => {
662	            let Number(n2) = b else { unreachable!("term class matched Number") };
663	            n1.cmp(n2)
664	        }
665	        NumberOne => std::cmp::Ordering::Equal,
666	        NatOne => std::cmp::Ordering::Equal,
667	        DhNeutral => std::cmp::Ordering::Equal,
668	        // HS derived `Ord (Term a)` for two FAPP terms compares the FunSym
669	        // first (for NoEq this is the function-name ByteString,
670	        // FunctionSymbols.hs:106,113-117) and then the operand list
671	        // element-wise (Term/Term/Raw.hs:72-74).  We approximate that here:
672	        // App compares by name then args; the other FAPP classes (already
673	        // separated by `class`) compare their operands element-wise.  This
674	        // gives a total order on the AC operand lists that arise, rather than
675	        // tying distinct complex operands as Equal.
676	        App(n1, a1) => {
677	            let App(n2, a2) = b else { unreachable!("term class matched App") };
678	            n1.cmp(n2).then_with(|| cmp_term_slices(a1, a2))
679	        }
680	        AlgApp(n1, l1, r1) => {
681	            let AlgApp(n2, l2, r2) = b else { unreachable!("term class matched AlgApp") };
682	            n1.cmp(n2)
683	                .then_with(|| cmp_wf_term(l1, l2))
684	                .then_with(|| cmp_wf_term(r1, r2))
685	        }
686	        Pair(a1) => {
687	            let Pair(a2) = b else { unreachable!("term class matched Pair") };
688	            cmp_term_slices(a1, a2)
689	        }
690	        Diff(l1, r1) => {
691	            let Diff(l2, r2) = b else { unreachable!("term class matched Diff") };
692	            cmp_wf_term(l1, l2).then_with(|| cmp_wf_term(r1, r2))
693	        }
694	        BinOp(o1, l1, r1) => {
695	            let BinOp(o2, l2, r2) = b else { unreachable!("term class matched BinOp") };
696	            (*o1 as u8).cmp(&(*o2 as u8))
697	                .then_with(|| cmp_wf_term(l1, l2))
698	                .then_with(|| cmp_wf_term(r1, r2))
699	        }
700	        PatMatch(i1) => {
701	            let PatMatch(i2) = b else { unreachable!("term class matched PatMatch") };
702	            cmp_wf_term(i1, i2)
703	        }
704	    }
705	}
706	
707	/// Lexicographic comparison of two operand lists by `cmp_wf_term`, with the
708	/// shorter list ordering first on a common prefix (matching Haskell's derived
709	/// `Ord [a]`).
710	fn cmp_term_slices(a: &[Term], b: &[Term]) -> std::cmp::Ordering {
711	    for (x, y) in a.iter().zip(b.iter()) {
712	        let o = cmp_wf_term(x, y);
713	        if o != std::cmp::Ordering::Equal { return o; }
714	    }
715	    a.len().cmp(&b.len())
716	}
717	
718	/// HS LSort declaration order (Term/LTerm.hs:161-166):
719	/// Pub < Fresh < Msg < Node < Nat.
720	fn sort_tag(s: &SortHint) -> u8 {
721	    use SortHint::*;
722	    use SuffixSort as SS;
723	    match s {
724	        Pub | Suffix(SS::Pub) => 0,
725	        Fresh | Suffix(SS::Fresh) => 1,
726	        Msg | Suffix(SS::Msg) | Untagged => 2,
727	        Node | Suffix(SS::Node) => 3,
728	        Nat | Suffix(SS::Nat) => 4,
729	    }
730	}
731	
732	fn sort_prefix(s: &SortHint) -> &'static str {
733	    use SortHint::*;
734	    use SuffixSort as SS;
735	    match s {
736	        Pub | Suffix(SS::Pub) => "$",
737	        Fresh | Suffix(SS::Fresh) => "~",
738	        Node | Suffix(SS::Node) => "#",
739	        Nat | Suffix(SS::Nat) => "%",
740	        Msg | Suffix(SS::Msg) | Untagged => "",
741	    }
742	}
743	
744	/// True if a sort hint indicates a fresh-sort variable.
745	fn is_fresh_sort(s: &SortHint) -> bool {
746	    matches!(s,
747	        SortHint::Fresh
748	        | SortHint::Suffix(SuffixSort::Fresh))
749	}
750	
751	fn is_msg_sort_or_untagged(s: &SortHint) -> bool {
752	    matches!(s, SortHint::Msg | SortHint::Untagged
753	        | SortHint::Suffix(SuffixSort::Msg))
754	}
755	
756	fn is_pub_sort(s: &SortHint) -> bool {
757	    matches!(s, SortHint::Pub | SortHint::Suffix(SuffixSort::Pub))
758	}
759	
760	fn is_nat_sort(s: &SortHint) -> bool {
761	    matches!(s, SortHint::Nat | SortHint::Suffix(SuffixSort::Nat))
762	}
