764	// =============================================================================
765	// Reserved fact names — Tamarin reserves 'fr', 'ku', 'kd', 'out', 'in'
766	// =============================================================================
767	
768	const RESERVED_FACT_NAMES: &[&str] = &["fr", "ku", "kd", "out", "in"];
769	
770	/// True if `name` is a built-in fact tag (case-insensitive). These are
771	/// allowed when used in their semantic position (e.g. `Fr(~k)` in a
772	/// premise) but not as user-defined protocol facts elsewhere.
773	fn is_builtin_fact_name(name: &str) -> bool {
774	    matches!(name, "Fr" | "In" | "Out" | "K" | "KU" | "KD" | "Ded" | "Term")
775	}
776	
777	pub fn reserved_report(thy: &Theory) -> WfReport {
778	    let mut out = Vec::new();
779	    for r in theory_rules(thy) {
780	        for (_, f) in rule_facts(r) {
781	            // Only protocol facts (non-builtin) trigger this check.
782	            if is_builtin_fact_name(&f.name) { continue; }
783	            let lower = f.name.to_lowercase();
784	            if RESERVED_FACT_NAMES.contains(&lower.as_str()) {
785	                out.push(WfError::new("Reserved names",
786	                    format!("Rule '{}' contains a fact with reserved name `{}`",
787	                        r.name, f.name)));
788	            }
789	        }
790	    }
791	    // Lemma/restriction formula facts: skipped here because the parser
792	    // AST keeps formulas in a less-structured form. This matches the
793	    // bulk of Tamarin's reserved_report behaviour for rules.
794	    out
795	}
