797	// =============================================================================
798	// Reserved KU/KD/K-log usage
799	// =============================================================================
800	
801	// HS `reservedFactNameRules'` (Wellformedness.hs:530-541) flags facts whose
802	// tag is `KUFact`/`KDFact` or which satisfy `isKLogFact` (a `ProtoFact "K"`,
803	// Fact.hs:319-320).  `Ded(..)` parses to tag `DedFact` (Fact.hs:285-286), which
804	// is in NONE of those sets, so it must NOT appear here.
805	const KLOG_NAMES: &[&str] = &["KU", "KD", "K"];
806	
807	pub fn reserved_fact_name_rules(thy: &Theory) -> WfReport {
808	    let mut out = Vec::new();
809	    for r in theory_rules(thy) {
810	        // HS checks the let-substituted `ProtoRuleE`, so the emitted facts
811	        // carry their fully-inlined terms (Term/Term/Raw.hs fAppAC order).
812	        let (prems, acts, concs) = rule_facts_with_lets(r);
813	        let bad_lhs: Vec<&Fact> = prems.iter()
814	            .filter(|f| KLOG_NAMES.contains(&f.name.as_str()))
815	            .collect();
816	        let bad_acts: Vec<&Fact> = acts.iter()
817	            .filter(|f| KLOG_NAMES.contains(&f.name.as_str())
818	                || matches!(f.name.as_str(), "In" | "Out" | "Fr"))
819	            .collect();
820	        let bad_rhs: Vec<&Fact> = concs.iter()
821	            .filter(|f| KLOG_NAMES.contains(&f.name.as_str()))
822	            .collect();
823	        for (msg, fs) in [
824	            ("on left-hand-side", bad_lhs),
825	            ("on the middle", bad_acts),
826	            ("on the right-hand-side", bad_rhs),
827	        ] {
828	            if !fs.is_empty() {
829	                // HS `reservedFactNameRules'` (Wellformedness.hs:530-550):
830	                //   (underlineTopic "Reserved names",
831	                //      text ("Rule " ++ quote (showRuleCaseName ru))
832	                //      <-> text ("contains facts with reserved names"++msg) $-$
833	                //      nest 2 (fsep $ punctuate comma $ map prettyLNFact fas))
834	                // grouped/nested by `prettyWfErrorReport` (text topic $-$
835	                // nest 2 body): the rule line gets 2-space indent, the fact
836	                // line 4-space (2 from ppTopic + 2 from the inner nest 2).
837	                let facts: Vec<String> =
838	                    fs.iter().map(|f| pp_wf_fact(f)).collect();
839	                // Headerless body (no trailing newline); `format_wf_block`
840	                // emits the single "Reserved names" header for the group and
841	                // joins per-rule/side bodies with the 2-space blank separator.
842	                let mut s = String::new();
843	                s.push_str(&format!(
844	                    "  Rule `{}' contains facts with reserved names {}:\n",
845	                    r.name, msg,
846	                ));
847	                s.push_str("    ");
848	                s.push_str(&facts.join(", "));
849	                out.push(WfError::new("Reserved names", s));
850	            }
851	        }
852	    }
853	    out
854	}
