857	// Reserved prefixes (DiffIntr*, DiffProto*) — diff theories only
858	// =============================================================================
859	
860	pub fn reserved_prefix_report(thy: &Theory) -> WfReport {
861	    // Port of HS `reservedPrefixReport` (Wellformedness.hs:796-808), diff
862	    // theories only.  HS groups ONE error per offending rule with body
863	    //   wrappedText ("The " ++ origin ++ " contains facts with reserved \
864	    //     prefixes ('DiffIntr', 'DiffProto') inside names:")
865	    //   $-$ map (nest 2) [prettyLNFact fa $-$ text (show factInfo)]
866	    // where `origin = "Rule " ++ quote (showRuleCaseName ru)` and
867	    // `quote cs = '`' : cs ++ "'"`.
868	    //
869	    // The faithful body needs HughesPJ `wrappedText` (greedy column-fill of the
870	    // header, which ALWAYS wraps here since the string exceeds the render
871	    // width) and `show factInfo` of the `(tag, arity, multiplicity)` tuple —
872	    // neither reproducible in the parser crate (the HughesPJ renderer lives in
873	    // `tamarin-theory`).  This check produces NO output on any corpus input, so
874	    // per the module-header disclaimer (only the topic string is guaranteed
875	    // byte-faithful) we emit a topic-faithful best-effort body and use the HS
876	    // `quote` form for the rule name.  topic "Reserved prefixes" matches HS
877	    // `underlineTopic`.
878	    let mut out = Vec::new();
879	    if !thy.is_diff { return out; }
880	    for r in theory_rules(thy) {
881	        for (_, f) in rule_facts(r) {
882	            let lower = f.name.to_lowercase();
883	            if lower.starts_with("diffintr") || lower.starts_with("diffproto") {
884	                out.push(WfError::new("Reserved prefixes",
885	                    format!("Rule `{}' contains a fact with reserved prefix: {}",
886	                        r.name, f.name)));
887	            }
888	        }
889	    }
890	    out
891	}
