894	// Special facts misuse
895	// =============================================================================
896	
897	pub fn special_facts_usage(thy: &Theory) -> WfReport {
898	    let mut out = Vec::new();
899	    for r in theory_rules(thy) {
900	        // HS `specialFactsUsage'` (Wellformedness.hs:553-566) reads
901	        // `get rPrems`/`get rConcs` on the closed `ProtoRuleE`, whose facts
902	        // carry their fully-inlined `let` terms — mirror the reserved-names
903	        // sibling and use the let-substituted facts.
904	        let (prems, _acts, concs) = rule_facts_with_lets(r);
905	        let lhs_bad: Vec<&Fact> = prems.iter()
906	            .filter(|f| f.name == "Out")
907	            .collect();
908	        let rhs_bad: Vec<&Fact> = concs.iter()
909	            .filter(|f| f.name == "Fr" || f.name == "In")
910	            .collect();
911	        for (msg, fs) in [
912	            ("on left-hand-side", lhs_bad),
913	            ("on right-hand-side", rhs_bad),
914	        ] {
915	            if !fs.is_empty() {
916	                // HS `specialFactsUsage'` (Wellformedness.hs:553-566):
917	                //   (underlineTopic "Special facts",
918	                //      text ("rule " ++ quote (showRuleCaseName ru)) <-> text msg
