1063	/// Walk a formula left-to-right (HS `foldFormula` order), collecting the fact
1064	/// of every `Action` atom together with its argument terms rendered in De
1065	/// Bruijn form (`Bound n` / `Free ...`).  `binders` is the enclosing
1066	/// quantifier stack (outermost first); the innermost binder has index 0.
1067	fn collect_formula_facts<'a>(
1068	    f: &'a Formula,
1069	    binders: &mut Vec<&'a VarSpec>,
1070	    out: &mut Vec<(Fact, Vec<String>)>,
1071	) {
1072	    match f {
1073	        Formula::Atom(Atom::Action(fa, _)) => {
1074	            let terms = fa.args.iter().map(|t| show_debruijn_term(t, binders)).collect();
1075	            out.push((fa.clone(), terms));
1076	        }
1077	        Formula::Atom(_) | Formula::True | Formula::False => {}
1078	        Formula::Not(a) => collect_formula_facts(a, binders, out),
1079	        Formula::And(a, b) | Formula::Or(a, b)
1080	        | Formula::Implies(a, b) | Formula::Iff(a, b) => {
1081	            collect_formula_facts(a, binders, out);
1082	            collect_formula_facts(b, binders, out);
1083	        }
1084	        Formula::Forall(vars, body) | Formula::Exists(vars, body) => {
1085	            let n = vars.len();
1086	            for v in vars { binders.push(v); }
1087	            collect_formula_facts(body, binders, out);
1088	            for _ in 0..n { binders.pop(); }
1089	        }
1090	    }
1091	}
