1391	    //         constants are not allowed:") : punctuate comma (map (show) names)
1392	    // where `quote cs = '`' : cs ++ "'"` (Wellformedness.hs:165) and the fresh
1393	    // names render via `show (Name FreshName n) = "~'" ++ n ++ "'"`
1394	    // (LTerm.hs:232).  Topic is "Fresh public constants"; the umbrella renderer
1395	    // emits the underlineTopic header once and 2-space-nests the bodies
1396	    // (separated by a `  ` blank line) — we bake that whole block into a single
1397	    // WfError so the default `format_wf_block` path reproduces the exact bytes.
1398	    let topic = "Fresh public constants";
1399	    let mut bodies: Vec<String> = Vec::new();
1400	    for r in theory_rules(thy) {
1401	        // HS `freshNamesReport` runs `universeBi` over the let-substituted
1402	        // `ProtoRuleE` (Wellformedness.hs:456), so a fresh name occurring
1403	        // only inside a `let` value (e.g. `let m = ~'foo' in ... Out(m)`) is
1404	        // inlined and surfaces here.  Mirror by walking the let-inlined facts.
1405	        let (prems, acts, concs) = rule_facts_with_lets(r);
1406	        let mut names = Vec::new();
1407	        for f in prems.iter().chain(&acts).chain(&concs) {
1408	            for t in &f.args {
1409	                term_name_lits(t, &mut names);
1410	            }
1411	        }
1412	        // HS `show (Name FreshName n) = "~'" ++ n ++ "'"` for each fresh name,
1413	        // joined by `punctuate comma` (`, `) under the `fsep`.
1414	        let fresh_lits: Vec<String> = names.iter()
1415	            .filter_map(|(k, n)| if *k == NameKind::Fresh {
1416	                Some(format!("~'{}'", n))
1417	            } else { None })
1418	            .collect();
1419	        if !fresh_lits.is_empty() {
1420	            // Body only, 2-space `nest 2` indent baked in; HS `quote` form for
1421	            // the rule name (backtick + apostrophe).
1422	            bodies.push(format!(
1423	                "  rule `{}': fresh public constants are not allowed: {}",
1424	                r.name, fresh_lits.join(", ")));
1425	        }
1426	    }
